// And groups predicates with the AND operator between them.
func And(predicates ...predicate.InventoryTxn) predicate.InventoryTxn {
	return predicate.InventoryTxn(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.InventoryTxn) predicate.InventoryTxn {
	return predicate.InventoryTxn(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.InventoryTxn) predicate.InventoryTxn {
	return predicate.InventoryTxn(sql.NotPredicates(p))
}
